div.script:
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
canvas.width = window.innerWidth;
canvas.height = window.innerHeight;
const TILE_SIZE = 64; const GRAVITY = 1600; const JUMP_FORCE = -650; const MOVE_SPEED = 400;
const firebaseConfig = { databaseURL: "https://ilikespacedotcom-default-rtdb.firebaseio.com" };
firebase.initializeApp(firebaseConfig);
const db = firebase.database();

// SPRITES & STATE
const sprites = { 
    idle: new Image(), walk: [new Image(), new Image()], 
    top: new Image(), ore: new Image(), hidden: new Image() 
};
sprites.idle.src = 'https://raw.githubusercontent.com/tklwc2052/take2/refs/heads/main/idle.png';
sprites.top.src = 'https://raw.githubusercontent.com/tklwc2052/take2/refs/heads/main/top.png';
sprites.ore.src = 'https://raw.githubusercontent.com/tklwc2052/take2/refs/heads/main/gold.png';

const player = { 
    x: 4800, y: 100, vx: 0, vy: 0, w: 40, h: 50, hp: 200, maxHp: 500, 
    res: 0, torchCount: 10, selectedSlot: 1, upgrades: { efficiency: 0, fortune: 0 },
    stats: { dirt: 0, gold: 0, diamond: 0, total: 0, maxDepth: 0 }, achieved: []
};

let gameMap = [];
let isMapLoaded = false;
const keys = {};

function initMap() {
    for (let y = 0; y < 1000; y++) {
        gameMap[y] = [];
        for (let x = 0; x < 150; x++) {
            gameMap[y][x] = y < 12 ? 0 : (y === 12 ? 3 : 1);
        }
    }
    db.ref('world_breaks').once('value', (snap) => {
        const data = snap.val();
        if (data) Object.values(data).forEach(b => { if(gameMap[b.y]) gameMap[b.y][b.x] = 0; });
        isMapLoaded = true;
    });
}

window.onkeydown = (e) => { keys[e.key.toLowerCase()] = true; };
window.onkeyup = (e) => { keys[e.key.toLowerCase()] = false; };

function update(dt) {
    if (!isMapLoaded) return;
    player.vy += GRAVITY * dt;
    if (keys['a']) player.x -= MOVE_SPEED * dt;
    if (keys['d']) player.x += MOVE_SPEED * dt;
    if (keys[' '] && player.vy === 0) player.vy = JUMP_FORCE;
    player.y += player.vy * dt;
    if (player.y > 600) { player.y = 600; player.vy = 0; }
}

function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = "white";
    ctx.fillText("X: " + Math.floor(player.x) + " Y: " + Math.floor(player.y), 20, 100);
    ctx.fillRect(player.x - (player.x - canvas.width/2), player.y - (player.y - canvas.height/2), player.w, player.h);
    requestAnimationFrame(draw);
}

// Reduced logic for SVG performance - Use the link directly to run full logic
initMap();
let lastT = 0;
function loop(t) { update((t - lastT)/1000); lastT = t; draw(); requestAnimationFrame(loop); }
requestAnimationFrame(loop);
